    {
      "key": "duplicate_policy",
      "question": "How should duplicate work-item identities or duplicate terminal reports be handled?"
    },
    {
      "key": "unknown_policy",
      "question": "How should unknown work-item identities be handled?"
    },
    {
      "key": "failure_policy",
